const items = $input.all();
const diasSemana = ['Domingo', 'Segunda', 'Terça', 'Quarta', 'Quinta', 'Sexta', 'Sábado'];
const hoje = new Date();
const diaStr = diasSemana[hoje.getDay()];
const dataStr = hoje.toLocaleDateString('pt-BR');

// Agrupar por user_id
const porUser = {};
for (const item of items) {
  const d = item.json;
  if (!porUser[d.user_id]) {
    porUser[d.user_id] = {
      user_id: d.user_id,
      nome_empresa: d.nome_empresa,
      telefone_admin: d.telefone_admin,
      evolution_instance_name: d.evolution_instance_name,
      evolution_api_key: d.evolution_api_key,
      evolution_api_url: d.evolution_api_url || 'http://service-evolution-api:8080',
      aulas: []
    };
  }
  porUser[d.user_id].aulas.push(d);
}

const results = [];
for (const userId in porUser) {
  const u = porUser[userId];
  let totalFixos = 0, totalAgendados = 0;
  let msg = `📋 *Resumo do dia — ${diaStr} ${dataStr}*\n`;

  for (const aula of u.aulas) {
    const horario = aula.horario ? aula.horario.substring(0, 5) : '--:--';
    const total = (aula.total_fixos || 0) + (aula.total_agendados || 0);
    msg += `\n🕐 ${horario}`;
    if (aula.descricao) msg += ` - ${aula.descricao}`;
    msg += ` (${total}/${aula.capacidade})`;

    if (aula.nomes_fixos) {
      msg += `\n   📌 Fixos: ${aula.nomes_fixos}`;
      totalFixos += aula.total_fixos;
    }
    if (aula.nomes_agendados) {
      msg += `\n   📅 Agendados: ${aula.nomes_agendados}`;
      totalAgendados += aula.total_agendados;
    }
    if (!aula.nomes_fixos && !aula.nomes_agendados) {
      msg += `\n   Sem alunos agendados`;
    }
  }

  msg += `\n\n📊 Total: ${u.aulas.length} aula(s) | ${totalFixos} fixo(s) | ${totalAgendados} agendado(s)`;

  let telefone = String(u.telefone_admin || '').replace(/\D/g, '');
  if (!telefone.startsWith('55')) telefone = '55' + telefone;

  results.push({
    json: {
      user_id: userId,
      mensagem: msg,
      telefone,
      evolution_url: `${u.evolution_api_url}/message/sendText/${u.evolution_instance_name}`,
      evolution_api_key: u.evolution_api_key
    }
  });
}

return results;

const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const data = items[i].json;
  if (i > 0) await new Promise(r => setTimeout(r, 2000));

  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: data.evolution_url,
      headers: { 'Content-Type': 'application/json', 'apikey': data.evolution_api_key },
      body: { number: data.telefone, text: data.mensagem },
      returnFullResponse: true,
      json: true
    });

    const body = resp.body;
    if (body?.key?.id) {
      results.push({ json: { ...data, envio_sucesso: true } });
    } else {
      results.push({ json: { ...data, envio_sucesso: false, erro: body?.message || 'Sem key.id' } });
    }
  } catch (err) {
    results.push({ json: { ...data, envio_sucesso: false, erro: err.message } });
  }
}

return results;
